"use client";

import { useState } from "react";

export default function Work() {
  const [hovered, setHovered] = useState<number | null>(null);
  const [heroHovered, setHeroHovered] = useState(false);

  const projects = [
    {
      image: "Film2.jpg",
      title: "LIVE EXPERIENCES",
      subtitle: "140K+ PEOPLE REACHED",
    },
    {
      image: "Film3.jpg",
      title: "BRANDED FILMS",
      subtitle: "CINEMATIC CAMPAIGNS",
    },
    {
      image: "Film1.jpg",
      title: "DOCUMENTARY",
      subtitle: "ON THE BRINK",
    },
  ];

  return (
    <section
      id="work"
      style={{
        background: "#020202",
        padding: "180px 40px",
        color: "#F9F4E6",
      }}
    >
      {/* HEADER */}
      <div
        style={{
          maxWidth: "1200px",
          margin: "0 auto 80px auto",
        }}
      >
        <h2
          style={{
            fontSize: "12px",
            letterSpacing: "3px",
            color: "#D24A16",
            marginBottom: "24px",
          }}
        >
          SELECTED WORK
        </h2>

        <p
          style={{
            fontSize: "clamp(34px, 5vw, 72px)",
            lineHeight: 1,
            maxWidth: "900px",
            margin: 0,
          }}
        >
          A collection of cinematic productions, live experiences and visual
          stories.
        </p>
      </div>

      {/* FEATURED PROJECT */}
      <div
        style={{
          maxWidth: "1200px",
          margin: "0 auto 30px auto",
          height: "80vh",
          minHeight: "600px",
          borderRadius: "24px",
          overflow: "hidden",
          position: "relative",
          cursor: "pointer",
        }}
        onMouseEnter={() => setHeroHovered(true)}
        onMouseLeave={() => setHeroHovered(false)}
      >
        <img
          src="/work/Film1.jpg"
          alt="On The Brink"
          style={{
            width: "100%",
            height: "100%",
            objectFit: "cover",
            transition: "all 0.8s ease",
            transform: heroHovered ? "scale(1.05)" : "scale(1)",
            filter: heroHovered ? "brightness(0.65)" : "brightness(1)",
          }}
        />

        <div
          style={{
            position: "absolute",
            inset: 0,
            background: heroHovered
              ? "linear-gradient(to top, rgba(0,0,0,0.92), rgba(0,0,0,0.4) 50%, transparent)"
              : "linear-gradient(to top, rgba(0,0,0,0.78), rgba(0,0,0,0.15) 45%, transparent)",
            transition: "all 0.5s ease",
          }}
        />

        <div
          style={{
            position: "absolute",
            left: "60px",
            bottom: "60px",
            zIndex: 2,
            transform: heroHovered
              ? "translateY(-10px)"
              : "translateY(0px)",
            transition: "all 0.35s ease",
          }}
        >
          <p
            style={{
              color: "#D24A16",
              letterSpacing: "3px",
              fontSize: "12px",
              marginBottom: "12px",
            }}
          >
            DOCUMENTARY SERIES
          </p>

          <h3
            style={{
              margin: 0,
              fontSize: "clamp(48px, 7vw, 110px)",
              lineHeight: 0.95,
            }}
          >
            ON THE BRINK
          </h3>
        </div>
      </div>

      {/* NETFLIX GRID */}
      <div
        style={{
          maxWidth: "1200px",
          margin: "0 auto",
          display: "grid",
          gridTemplateColumns: "repeat(3, 1fr)",
          gap: "24px",
        }}
      >
        {projects.map((project, i) => (
          <div
            key={i}
            onMouseEnter={() => setHovered(i)}
            onMouseLeave={() => setHovered(null)}
            style={{
              height: "340px",
              borderRadius: "18px",
              overflow: "hidden",
              position: "relative",
              cursor: "pointer",
            }}
          >
            <img
              src={`/work/${project.image}`}
              alt={project.title}
              style={{
                width: "100%",
                height: "100%",
                objectFit: "cover",
                transition: "all 0.6s ease",
                transform:
                  hovered === i ? "scale(1.08)" : "scale(1)",
                filter:
                  hovered === i
                    ? "brightness(0.45)"
                    : "brightness(1)",
              }}
            />

            <div
              style={{
                position: "absolute",
                inset: 0,
                background:
                  hovered === i
                    ? "linear-gradient(to top, rgba(0,0,0,0.92), rgba(0,0,0,0.3) 55%, transparent)"
                    : "linear-gradient(to top, rgba(0,0,0,0.75), transparent 60%)",
                transition: "all 0.35s ease",
              }}
            />

            <div
              style={{
                position: "absolute",
                left: "24px",
                bottom: "24px",
                transform:
                  hovered === i
                    ? "translateY(-8px)"
                    : "translateY(0px)",
                transition: "all 0.35s ease",
              }}
            >
              <p
                style={{
                  margin: 0,
                  color: "#D24A16",
                  fontSize: "11px",
                  letterSpacing: "2px",
                  marginBottom: "8px",
                }}
              >
                {project.title}
              </p>

              <h4
                style={{
                  margin: 0,
                  fontSize: "22px",
                  lineHeight: 1.2,
                  maxWidth: "250px",
                }}
              >
                {project.subtitle}
              </h4>
            </div>
          </div>
        ))}
      </div>
    </section>
  );
}